(function(w){"use strict";const ID="standard-weight";function compute(x){const h=Number(x.height),bmi=Number(x.bmi||22);if(!Number.isFinite(h)||h<=0||!Number.isFinite(bmi)||bmi<=0)return{error:"키와 기준 BMI를 올바르게 입력해 주세요."};return{weight:bmi*Math.pow(h/100,2)}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>키 (cm)</label><input class="hm-calc-input" inputmode="decimal" placeholder="예: 170"></div><div class="hm-calc-field"><label>기준 BMI</label><input class="hm-calc-input" inputmode="decimal" value="22"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">표준체중 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div><p class="hm-calc-note">BMI 22는 참고 기준이며 개인의 적정체중을 진단하는 값이 아닙니다.</p></div>`;const [h,bmi]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({height:api.parseNumber(h.value),bmi:api.parseNumber(bmi.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("참고 표준체중",`${api.formatNumber(r.weight,1)} kg`));});}w.HM_CALC.register(ID,{compute,render});})(window);
